import pytest
import requests
from datetime import datetime, timedelta

def test_non_admin_role_forbidden_create_task(user_token, api_base_url):
    payload = {
        "title": "Onboarding Task",
        "description": "Complete orientation",
        "assignee_id": "user-123",
        "due_date": (datetime.now() + timedelta(days=7)).isoformat()
    }
    headers = {"Authorization": f"Bearer {user_token}"}
    resp = requests.post(
        f"{api_base_url}/onboarding-tasks",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 403
    data = resp.json()
    assert any(kw in data.get("message", "").lower() 
               for kw in ["forbidden", "insufficient", "permission"])
